#!/bin/bash

prep() {
  mkdir -p html

  # Read allocated IP: parse .rediacc.json for slot, calculate IP from network range
  # Network range base is derived from network ID. Renet allocates IPs as base+2+slot.
  # We can detect the IP by looking at loopback aliases in our /26 range.
  # The IP is on the lo interface in the 127.0.x.x range allocated for this repo.
  WEB_IP=$(ip -4 addr show lo | grep -oP '127\.0\.15\.[0-9]+' | grep -v '127.0.15.64' | head -1)
  if [ -z "$WEB_IP" ]; then
    echo "ERROR: Could not detect allocated loopback IP"
    exit 1
  fi
  echo "Binding nginx to $WEB_IP:8080"

  cat > html/index.html << 'HTMLEOF'
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <meta name="description" content="OpenClaw - AI-powered legal assistant for modern law firms and legal professionals.">
  <meta name="keywords" content="AI, legal, assistant, law, automation, OpenClaw">
  <meta name="author" content="OpenClaw">
  <title>OpenClaw - AI Legal Assistant</title>
  <style>
    *, *::before, *::after { margin: 0; padding: 0; box-sizing: border-box; }
    :root {
      --primary: #1a365d;
      --primary-light: #2b6cb0;
      --accent: #ed8936;
      --bg: #f7fafc;
      --text: #2d3748;
      --text-light: #718096;
      --white: #ffffff;
      --shadow: 0 4px 6px -1px rgba(0,0,0,0.1), 0 2px 4px -1px rgba(0,0,0,0.06);
      --shadow-lg: 0 20px 25px -5px rgba(0,0,0,0.1), 0 10px 10px -5px rgba(0,0,0,0.04);
    }
    body {
      font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, "Helvetica Neue", Arial, sans-serif;
      background: var(--bg);
      color: var(--text);
      line-height: 1.6;
    }
    header {
      background: linear-gradient(135deg, var(--primary) 0%, var(--primary-light) 100%);
      color: var(--white);
      padding: 1rem 2rem;
      box-shadow: var(--shadow);
      position: sticky;
      top: 0;
      z-index: 100;
    }
    .header-inner {
      max-width: 1200px;
      margin: 0 auto;
      display: flex;
      align-items: center;
      justify-content: space-between;
    }
    .logo {
      font-size: 1.5rem;
      font-weight: 700;
      letter-spacing: -0.025em;
    }
    .logo span { color: var(--accent); }
    nav a {
      color: rgba(255,255,255,0.85);
      text-decoration: none;
      margin-left: 2rem;
      font-size: 0.95rem;
      font-weight: 500;
      transition: color 0.2s;
    }
    nav a:hover { color: var(--white); }
    .hero {
      background: linear-gradient(135deg, var(--primary) 0%, #2c5282 50%, var(--primary-light) 100%);
      color: var(--white);
      padding: 6rem 2rem;
      text-align: center;
    }
    .hero h1 {
      font-size: 3rem;
      font-weight: 800;
      margin-bottom: 1.5rem;
      letter-spacing: -0.025em;
      line-height: 1.2;
    }
    .hero p {
      font-size: 1.25rem;
      max-width: 600px;
      margin: 0 auto 2.5rem;
      opacity: 0.9;
      line-height: 1.7;
    }
    .cta-button {
      display: inline-block;
      background: var(--accent);
      color: var(--white);
      padding: 0.875rem 2.5rem;
      border-radius: 8px;
      text-decoration: none;
      font-weight: 600;
      font-size: 1.1rem;
      transition: transform 0.2s, box-shadow 0.2s;
      box-shadow: var(--shadow);
    }
    .cta-button:hover {
      transform: translateY(-2px);
      box-shadow: var(--shadow-lg);
    }
    .features {
      max-width: 1200px;
      margin: -3rem auto 4rem;
      padding: 0 2rem;
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
      gap: 2rem;
      position: relative;
      z-index: 10;
    }
    .feature-card {
      background: var(--white);
      border-radius: 12px;
      padding: 2.5rem 2rem;
      box-shadow: var(--shadow-lg);
      transition: transform 0.2s;
    }
    .feature-card:hover { transform: translateY(-4px); }
    .feature-icon {
      width: 48px;
      height: 48px;
      background: linear-gradient(135deg, var(--primary), var(--primary-light));
      border-radius: 12px;
      display: flex;
      align-items: center;
      justify-content: center;
      margin-bottom: 1.25rem;
      font-size: 1.5rem;
    }
    .feature-card h3 {
      font-size: 1.25rem;
      margin-bottom: 0.75rem;
      color: var(--primary);
    }
    .feature-card p {
      color: var(--text-light);
      font-size: 0.95rem;
      line-height: 1.7;
    }
    .section {
      max-width: 1200px;
      margin: 0 auto;
      padding: 4rem 2rem;
    }
    .section h2 {
      font-size: 2rem;
      text-align: center;
      margin-bottom: 1rem;
      color: var(--primary);
    }
    .section .subtitle {
      text-align: center;
      color: var(--text-light);
      max-width: 600px;
      margin: 0 auto 3rem;
      font-size: 1.1rem;
    }
    .stats {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
      gap: 2rem;
      text-align: center;
    }
    .stat h3 {
      font-size: 2.5rem;
      color: var(--primary-light);
      font-weight: 800;
    }
    .stat p {
      color: var(--text-light);
      margin-top: 0.5rem;
    }
    footer {
      background: var(--primary);
      color: rgba(255,255,255,0.7);
      text-align: center;
      padding: 2rem;
      margin-top: 4rem;
      font-size: 0.9rem;
    }
    footer a { color: var(--accent); text-decoration: none; }
    @media (max-width: 768px) {
      .hero h1 { font-size: 2rem; }
      .hero { padding: 4rem 1.5rem; }
      nav a { margin-left: 1rem; font-size: 0.85rem; }
    }
  </style>
</head>
<body>
  <header>
    <div class="header-inner">
      <div class="logo">Open<span>Claw</span></div>
      <nav>
        <a href="#features">Features</a>
        <a href="#metrics">Metrics</a>
        <a href="#contact">Contact</a>
      </nav>
    </div>
  </header>

  <section class="hero">
    <h1>AI-Powered Legal Intelligence</h1>
    <p>Streamline legal research, contract analysis, and compliance workflows with cutting-edge artificial intelligence built for modern law firms.</p>
    <a href="#features" class="cta-button">Explore Features</a>
  </section>

  <div class="features" id="features">
    <div class="feature-card">
      <div class="feature-icon">&#9878;</div>
      <h3>Contract Analysis</h3>
      <p>Automatically review and analyze contracts, identifying key clauses, risks, and obligations in seconds rather than hours.</p>
    </div>
    <div class="feature-card">
      <div class="feature-icon">&#128269;</div>
      <h3>Legal Research</h3>
      <p>Search across case law, statutes, and regulations with AI that understands legal context and precedent relationships.</p>
    </div>
    <div class="feature-card">
      <div class="feature-icon">&#9989;</div>
      <h3>Compliance Monitoring</h3>
      <p>Stay ahead of regulatory changes with real-time monitoring and automated compliance assessment across jurisdictions.</p>
    </div>
  </div>

  <section class="section" id="metrics">
    <h2>Trusted by Legal Professionals</h2>
    <p class="subtitle">OpenClaw is transforming how legal teams work, delivering measurable results across every practice area.</p>
    <div class="stats">
      <div class="stat">
        <h3>95%</h3>
        <p>Time saved on contract review</p>
      </div>
      <div class="stat">
        <h3>10k+</h3>
        <p>Legal documents analyzed daily</p>
      </div>
      <div class="stat">
        <h3>500+</h3>
        <p>Law firms worldwide</p>
      </div>
      <div class="stat">
        <h3>99.9%</h3>
        <p>Platform uptime</p>
      </div>
    </div>
  </section>

  <footer id="contact">
    <p>&copy; 2026 OpenClaw. All rights reserved. | <a href="mailto:contact@openclaw.ai">contact@openclaw.ai</a></p>
  </footer>
</body>
</html>
HTMLEOF

  cat > nginx.conf << NGINXEOF
server {
    listen ${WEB_IP}:8080;
    server_name openclaw.rediacc.io localhost;

    root /usr/share/nginx/html;
    index index.html;

    location / {
        try_files \$uri \$uri/ /index.html;
    }

    location ~* \\.(css|js|png|jpg|jpeg|gif|ico|svg|woff|woff2)\$ {
        expires 30d;
        add_header Cache-Control "public, immutable";
    }

    gzip on;
    gzip_types text/plain text/css application/json application/javascript text/xml application/xml text/javascript;
    gzip_min_length 256;
}
NGINXEOF

  renet compose -- pull
}

up() {
  renet compose -- up -d
}

down() {
  renet compose -- down
}

info() {
  echo "OpenClaw - AI Legal Assistant"
  echo "Port: 8080"
  echo "Domain: openclaw.rediacc.io"
}
